          "type": "string",
          "enum": [
            "organization",
            "user"
          ]
        },
        "owner_login": {
          "type": "string",
          "minLength": 1
        },
        "project_number": {
          "type": "integer",
          "minimum": 1
        },
        "project_id": {
          "type": [
            "string",
            "null"
          ]
        },
        "item_id": {
          "type": [
            "string",
            "null"
          ]
        },
        "sync_state": {
          "type": "string",
          "enum": [
            "unlinked",
            "linked",
            "synced",
            "pending_retry",
            "conflict",
            "detached"
          ]
        },
        "field_snapshot": {
          "type": "object",
          "additionalProperties": {
            "type": [
              "string",
              "number",
              "boolean",
              "null"
            ]
          }
        },
        "linked_at": {
          "type": [
            "string",
            "null"
          ],
          "format": "date-time"
        },
        "last_synced_at": {
          "type": [
            "string",
            "null"
          ],
          "format": "date-time"
        },
        "last_error_code": {
          "type": [
            "string",
            "null"
          ]
        }
      }
    }
  },
  "pull_request_linkages": {
    "type": "array",
    "uniqueItems": true,
    "items": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "repo",
        "pr_number",
        "url",
        "base_branch",
        "head_branch",
        "state",
        "merged_at",
        "merge_commit_sha",
        "linked_at",
        "closing_reference_verified"
