        "pr_number": {
          "type": "integer",
          "minimum": 1
        },
        "url": {
          "type": "string",
          "format": "uri"
        },
        "base_branch": {
          "type": "string",
          "minLength": 1
        },
        "head_branch": {
          "type": "string",
          "minLength": 1
        },
        "state": {
          "type": "string",
          "enum": [
            "open",
            "closed_unmerged",
            "merged"
