    "template": "common-frontmatter.md",
    "required": ["graph_node_id", "artifact_kind", "artifact_subtypes", "title", "project_id", "domain", "status", "priority", "start_date", "target_date", "iteration", "owners", "tags", "file_path", "template_id", "template_version", "confirmation_status", "evaluation_status", "confirmation_evidence", "source_lineage", "created_at", "updated_at", "depends_on", "related_nodes", "resource_scope", "purpose", "goal", "scope_in", "scope_out", "acceptance", "architecture_refs", "parent_feature", "feature_package_id", "phase_ref", "classification_confidence", "classification_reason", "classification_candidates", "tracker_binding", "beads_linkage", "github_publication", "issue_linkage", "github_project_linkages", "pull_request_linkages", "execution_contexts", "completion_evidence", "implementation_readiness"]
  },
  "artifacts": {
    "issue": {
      "template": "issue.md",
      "required_sections": ["概要", "背景と問題", "現在の挙動", "期待する挙動", "再現手順またはユースケース", "影響と優先度", "スコープ", "関連グラフ", "受入条件", "検証証跡"]
    },
    "task": {
      "template": "task.md",
      "required_sections": ["目的", "背景", "入力と前提条件", "出力と成果物", "依存関係", "実装対象", "Write scope と競合制約", "GitHub publication", "実行手順", "受入条件", "検証方法", "リスクとロールバック", "Handoff"],
      "conditional_templates": {"system_development": "system-task-spec.md"},
      "conditional_required_sections": {"system_development": ["Workstream applicability", "Architecture and deploy unit", "Verification and evidence", "Rollout and rollback", "Tracker publication and completion intent"]}
    },
